    -(void)loadWebContentFromHtml:(NSString *)html {

        if (self.webView == nil){
            self.webView = [SFAwkWebView aft_wkWebViewWithFrame:CGRectMake(0, 0, kScreenWidth, kScreenHeight - 64)];

            NSURL *htmlFileUrl = [[NSBundle mainBundle] URLForResource:@"index" withExtension:@"html"];
            self.webView.loadHtmlFromUrl:htmlFileUrl;

            [self.view addSubview:self.webView];

            NSData* data = [@"test" dataUsingEncoding:NSUTF8StringEncoding];
            [self.webView registerHandlerForName:@"<message>" withData:data];
        }
    }

    -(void)webView:(WKWebView *)webView didFinishNavigation:(WKNavigation *)navigation {

